from typing import Optionalfrom api.client.http_client import HttpClientclass IdmAuthMethod(HttpClient):    """    Методы группы 'Авторизация' из https://im-docs.corp.mail.ru/    """    def idm_auth_authorize(        self,        url,        client_id: str,        response_type: str,        redirect_uri: str,        login_hint: Optional[str] = None,        _type: Optional[str] = None,        state: Optional[str] = None,        scope: Optional[str] = None,        locale: Optional[str] = None,    ) -> dict:        """        Получение формы аутентификации либо формы выбора провайдера        Получение формы аутентификации либо формы выбора провайдера        :param client_id: Идентификатор приложения        :param response_type: Тип запрашиваемых данных        :param redirect_uri: Адрес, на который будет возвращен результат запроса        :param login_hint: Подсказка к логину пользователя        :param _type: Тип аутентификации для определения формы аутентификации стороннего сервиса        :param state: Уникальный идентификатор запроса, для предотвращения CSRF-атак        :param scope: Доступы для дальнейших запросов        :param locale: Локализация пользователя        :return: тело ответа сервера        """        return self.get(            url + "/api/v133/idm/auth/authorize",            params={                "allow_redirects": False,                "client_id": client_id,                "response_type": response_type,                "redirect_uri": redirect_uri,                "login_hint": login_hint,                "type": _type,                "state": state,                "scope": scope,                "locale": locale,            },            allow_redirects=False,        )    def idm_auth_token(        self,        url,        client_secret: str,        grant_type: str,        client_id: Optional[str] = None,        code: Optional[str] = None,        redirect_uri: Optional[str] = None,        scope: Optional[str] = None,        state: Optional[str] = None,        silent_token: Optional[str] = None,        miniapp_access_ttl: Optional[int] = None,        refresh_token: Optional[str] = None,    ) -> dict:        """        Получение либо обновление токенов        :param client_id: Идентификатор приложения        :param client_secret: Секретный ключ приложения        :param grant_type: тип прав выдаваемого токена        :param code: код авторизации, обязателен в случае grant_type authorization_code        :param redirect_uri: должен быть идентичен урлу из запроса authorize в случае grant_type authorization_code        :param refresh_token: обязателен в случае grant_type refresh_token        :param scope: Доступы для дальнейших запросов        :param state: Уникальный идентификатор запроса, для предотвращения CSRF-атак        :param silent_token: silent token        :param miniapp_access_ttl: miniapp ttl. 600        :return: тело ответа сервера        """        return self.post(            url + "/api/v133/idm/auth/token",            data={                "client_id": client_id,                "client_secret": client_secret,                "grant_type": grant_type,                "code": code,                "refresh_token": refresh_token,                "scope": scope,                "state": state,                "silent_token": silent_token,                "miniapp_access_ttl": miniapp_access_ttl,                "redirect_uri": redirect_uri,            },        )    def idm_auth_revoke(        self,        url,        client_id: str,        token: str,        client_secret: Optional[str] = None,        token_type_hint: Optional[str] = None,    ) -> dict:        """        Отзыв токена        :param client_id: Идентификатор приложения        :param token: Токен который необходимо удалить        :param client_secret: Секретный ключ приложения        :param token_type_hint: Тип токена, который нужно удалить; для облегчения поиска        :return: тело ответа сервера        """        return self.post(            url + "/api/v133/idm/auth/revoke",            data={                "client_id": client_id,                "client_secret": client_secret,                "token": token,                "token_type_hint": token_type_hint,            },        )    def idm_auth_callback(self, url, code: str, state: Optional[str] = None) -> dict:        """        Внутренний метод перенаправления данных от провайдера к клиенту        :param code: Код авторизации        :param state: Уникальный идентификатор запроса, для предотвращения CSRF-атак        :return: тело ответа сервера        """        return self.get(            url + "/api/v133/idm/auth/callback",            code=code,            state=state,        )    def idm_auth_validate(self, url, access_token: str) -> dict:        """        Внутренний метод проверки валидности токена        :param access_token: Токен        :return: тело ответа сервера        """        return self.post(            url + "/api/v133/idm/auth/validate",            json={                "access_token": f"Bearer {access_token}",            },        )    def idm_auth_userinfo(self, url, access_token: str) -> dict:        """        Внутренний метод проверки валидности токена        :param access_token: Токен        :return: тело ответа сервера        """        return self.get(url + "/api/v133/idm/auth/userinfo", headers={"Authorization": f"Bearer {access_token}"})    def idm_auth_token_silent(self, url, access_token: str, client_id: str, grant_type: str) -> dict:        """        Внутренний метод проверки валидности токена        :param access_token: Токен        :param client_id: Идентификатор приложения        :param grant_type: тип прав выдаваемого токена        :return: тело ответа сервера        """        return self.post(            url + "/api/v133/idm/auth/token/silent",            headers={"Authorization": f"Bearer {access_token}"},            data={                "client_id": client_id,                "grant_type": grant_type,            },        ).json()